public class RegressionMetrics {

    // Calculate Mean Squared Error
    public static double calculateMSE(double[] actual, double[] predicted) {
        if (actual.length != predicted.length) {
            throw new IllegalArgumentException("Arrays must have same length");
        }

        double sumSquaredError = 0.0;
        int n = actual.length;

        for (int i = 0; i < n; i++) {
            double error = actual[i] - predicted[i];
            sumSquaredError += error * error;
        }

        return sumSquaredError / n;
    }

    // Calculate R-Squared
    public static double calculateRSquared(double[] actual, double[] predicted) {
        double meanActual = calculateMean(actual);
        double ssTot = 0.0;  // Total sum of squares
        double ssRes = 0.0;  // Residual sum of squares

        for (int i = 0; i < actual.length; i++) {
            ssTot += Math.pow(actual[i] - meanActual, 2);
            ssRes += Math.pow(actual[i] - predicted[i], 2);
        }

        return 1 - (ssRes / ssTot);
    }

    private static double calculateMean(double[] arr) {
        double sum = 0;
        for (double val : arr) sum += val;
        return sum / arr.length;
    }

    public static void main(String[] args) {
        double[] actual = {3.0, 4.0, 5.0, 6.0, 7.0};
        double[] predicted = {3.1, 4.2, 4.9, 6.2, 6.8};

        System.out.println("MSE: " + calculateMSE(actual, predicted));
        System.out.println("R-Squared: " + calculateRSquared(actual, predicted));
    }
}
